function toRawShape(inputSchema) {
  const schema = inputSchema;
  if (schema?.properties === undefined)
    return {};
  try {
    const zodSchema = jsonSchemaToZod(schema);
    return zodSchema instanceof exports_external.ZodObject ? zodSchema.shape : { input: exports_external.any() };
  } catch {
    return {};
  }
}
function headerValue(raw) {
  if (raw === undefined)
    return;
  return Array.isArray(raw) ? raw[0] : raw;
}

// spike/sp1/bridge_park_e2e.ts
var MAGIC = "BRIDGE-PARK-9ZZ7";
var sleep2 = (ms) => new Promise((r2) => setTimeout(r2, ms));
async function main() {
  const bridge = new ToolBridge;
  const key = "k1";
  const h = await bridge.ensure(key, [{ name: "get_build_code" }]);
  console.log(`[bridge] mcpConfig=${h.mcpConfigArg()}`);
  console.log(`[bridge] allowedTools=${JSON.stringify(h.allowedToolNames())}`);
  const claudePath = join3(homedir2(), ".local/bin/claude");
  const cwd = mkdtempSync(join3(tmpdir(), "sp1-bridge-park-"));
  const sess = new ClaudeSession(claudePath, cwd, [
    "--settings",
    '{"remoteControlAtStartup":false}',
    "--mcp-config",
    h.mcpConfigArg(),
    "--strict-mcp-config",
    "--tools",
    "",
    "--allowedTools",
    ...h.allowedToolNames()
  ], { mode: "clean" });
  let resumed = false;
  const pump = (async () => {
    const handle = bridge.handle(key);
    if (handle === undefined)
      throw new Error("missing bridge handle");
    while (!resumed) {
      const parked = handle.peekParkedCall();
      if (parked !== null) {
        console.log(`[bridge] parked call ${parked.id} name=${parked.name} input=${JSON.stringify(parked.input)}`);
        handle.resume(parked.id, MAGIC);
        resumed = true;
        break;
      }
      await sleep2(100);
    }
  })();
  try {
    const ready = await sess.ready();
    console.log("ready:", ready);
    const t02 = Date.now();
    const r2 = await sess.turn("Use the get_build_code tool, then reply with exactly: BUILD=<the code it returned>", undefined, async (p4) => p4.defaultIndex);
    await pump;
    console.log(`turn ${Date.now() - t02}ms done=${r2.doneDetected} resumed=${resumed} text=${JSON.stringify(r2.text)}`);
    const pass = resumed && r2.text.includes(MAGIC);
    console.log(pass ? "BRIDGE_PARK: PASS" : "BRIDGE_PARK: FAIL");
    process.exit(pass ? 0 : 1);
  } finally {
    await sess.close();
    await bridge.close();
  }
}
main().catch((e2) => {
  console.error("[ERR]", e2);
  process.exit(1);
});
